{
  "formal_minutes": {
    "decisions": [
      "공개 릴리스 목표는 스모크 테스트 통과 시 금요일 15:00 KST로 한다.",
      "packageName 불일치가 발생하면 먼저 패키지 설정을 확인한다.",
      "계약 자체가 잘못된 경우에만 smoke-theme-pack.mjs 스크립트를 검토한다."
    ],
    "non_decisions": {
      "rejected_proposals": [
        "smoke-theme-pack.mjs가 packageName 불일치를 무시하도록 변경하자는 Hara의 제안은 거절되었다."
      ],
      "internal_stretch_goals": [
        "수요일 릴리스는 확정 일정이 아니라 내부 stretch goal이다."
      ],
      "unassigned_or_unconfirmed": [
        "README 설치 단계는 목요일까지 검토하면 좋다는 의견이 있었지만, 담당자는 지정되지 않았다.",
        "Hara는 Minjun이 스모크 결과를 공유한 뒤 생성된 tarball 경로를 확인하기로 했지만, 정확한 마감 시각은 정해지지 않았다."
      ]
    },
    "risks": [
      "잘못된 tarball 경로는 릴리스를 지연시킬 수 있다.",
      "README 설치 단계가 오래된 상태라면 릴리스 노트가 사용자를 오도할 수 있다."
    ],
    "open_questions": [
      "최종 릴리스 승인 권한자는 누구인가?",
      "릴리스 노트에 내부 수요일 stretch goal을 언급해야 하는가?"
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "confirmed"
    },
    {
