    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 게시한 뒤 생성된 tarball 경로를 확인한다.",
      "due": null,
      "status": "확정된 작업이나 정확한 마감 없음",
      "source_certainty": "confirmed_no_exact_deadline"
    },
    {
      "owner": null,
      "task": "README 설치 단계를 검토한다.",
      "due": "목요일까지 가능하면",
      "status": "담당자 미정, 확정 작업 아님",
      "source_certainty": "suggested_unassigned"
    }
  ],
  "followup_note": {
    "check_next": [
      "Minjun의 금요일 10:00 KST 스모크 테스트 결과 공유 여부를 확인한다.",
      "Doyun의 금요일 12:00 KST action_items.md failure triage note 작성 여부를 확인한다.",
